#include "prototype.h"

void gameOver(){
    setBackgroundColor(7, 7, 7);
    renderBitmap(80, 60, gameOver);
}

void startGame(int option){
    setBackgroundColor(7, 7, 7);
    option == 1 ? renderBitmap(80, 60, inital_screenOP1) : renderBitmap(80, 60, inital_screenOP2);
}

void renderBitmap(int width, int height, int bitmap[HEIGHT][WIDTH]) {

    int colors[7][3] = {{0, 0, 0}, {0, 0, 7}, {0, 7, 0}, {0, 7, 7}, {7, 0, 0}, {7, 0, 7}, {7, 7, 0}};
    int c = 0;

    for (int i = 0; i < height; i++) {
        (c == 6) ? c = 0 : c++;
        for (int j = 0; j < width; j++) {
            if (bitmap[i][j] == 1) {
                setBackgroundBlock(j, i, colors[c][0], colors[c][1], colors[c][2]);
            }
        }
    }
}


